import src.checkpointer as cp_mod

# Test edge cases
class TestPool:
    def __init__(self, name, behavior):
        self.name = name
        self.behavior = behavior

    def close(self):
        if self.behavior == 'normal':
            pass
        elif self.behavior == 'exception':
            raise RuntimeError('Pool close failed')
        elif self.behavior == 'other_exception':
            raise ValueError('Other error')

# Test 1: Normal close works
pool_normal = TestPool('normal', 'normal')
try:
    cp_mod._safe_close(pool_normal)
    print('Test 1 (normal): PASS')
except:
    print('Test 1 (normal): FAIL')

# Test 2: Exception is swallowed
pool_bad = TestPool('bad', 'exception')
try:
    cp_mod._safe_close(pool_bad)
    print('Test 2 (exception): PASS')
except:
    print('Test 2 (exception): FAIL')

# Test 3: Other exception types are also swallowed
pool_other = TestPool('other', 'other_exception')
try:
    cp_mod._safe_close(pool_other)
    print('Test 3 (other_exception): PASS')
except:
    print('Test 3 (other_exception): FAIL')

# Test 4: Function returns None (as indicated by -> None)
pool_test = TestPool('test', 'normal')
result = cp_mod._safe_close(pool_test)
if result is None:
    print('Test 4 (returns None): PASS')
else:
    print(f'Test 4 (returns None): FAIL - got {result}')
